        elseif(ctype_digit($segments[1])){$id=(int)$segments[1];$queries=['contacts'=>["SELECT CONCAT(first_name,' ',last_name) FROM contacts WHERE id=?",'Contact'],'companies'=>['SELECT name FROM companies WHERE id=?','Company'],'opportunities'=>['SELECT title FROM opportunities WHERE id=?','Opportunity'],'events'=>['SELECT title FROM events WHERE id=?','Event']];$stmt=db()->prepare($queries[$section][0]);$stmt->execute([$id]);$label=$stmt->fetchColumn()?:$queries[$section][1];$crumbs[]=[$label,'/'.$section.'/'.$id];if(($segments[2]??'')==='edit')$crumbs[]=['Edit',null];}
