function contact_tags(int $id): array { $s=db()->prepare('SELECT t.* FROM tags t JOIN contact_tags ct ON ct.tag_id=t.id WHERE ct.contact_id=? ORDER BY t.name');$s->execute([$id]);return $s->fetchAll(); }
