function sync_tags(int $contactId, array $tagIds): void { db()->prepare('DELETE FROM contact_tags WHERE contact_id=?')->execute([$contactId]);$s=db()->prepare('INSERT INTO contact_tags(contact_id,tag_id) VALUES(?,?)');foreach(array_unique(array_map('intval',$tagIds)) as $id)if($id&&tag_access($id)==='write')$s->execute([$contactId,$id]); }
function render_contact_custom_fields(?int $contactId,array $selectedTags): void {
    $values=[];if($contactId){$stmt=db()->prepare('SELECT custom_field_id,field_value FROM contact_custom_values WHERE contact_id=?');$stmt->execute([$contactId]);$values=array_column($stmt->fetchAll(),'field_value','custom_field_id');}
    $fields=custom_field_definitions();if(!$fields)return;$groups=[];foreach($fields as $field)$groups[$field['group_name']?:'Other information'][]=$field;echo '<div class="full custom-fields"><h2>Custom fields</h2>';
    foreach($groups as $groupName=>$groupFields){echo '<section class="custom-field-group"><h3>'.e($groupName).'</h3><div class="form-grid">';foreach($groupFields as $field){$applicable=!$field['tag_ids']||array_intersect($field['tag_ids'],$selectedTags);foreach($field['conditions'] as $condition)if(!custom_condition_matches($condition,(string)($values[(int)$condition['depends_on_field_id']]??'')))$applicable=false;$conditions=e(json_encode(array_map(fn($c)=>['depends_on_field_id'=>(int)$c['depends_on_field_id'],'operator'=>$c['operator'],'expected_value'=>$c['expected_value']],$field['conditions']),JSON_HEX_APOS|JSON_HEX_QUOT));echo '<label class="custom-field" data-condition-tags="'.e(implode(',',$field['tag_ids'])).'" data-field-conditions="'.$conditions.'"'.($applicable?'':' hidden').'>';echo e($field['name']);$value=$values[$field['id']]??'';
        if($field['field_type']==='list'){echo '<select name="custom_fields['.(int)$field['id'].']"'.($applicable?'':' disabled').'><option value="">Choose…</option>';foreach($field['options'] as $option)echo '<option value="'.e($option['option_value']).'"'.($value===$option['option_value']?' selected':'').'>'.e($option['option_value']).'</option>';echo '</select>';}
        elseif($field['field_type']==='textarea')echo '<textarea name="custom_fields['.(int)$field['id'].']"'.($field['required']?' required':'').($applicable?'':' disabled').'>'.e($value).'</textarea>';elseif($field['field_type']==='checkbox')echo '<select name="custom_fields['.(int)$field['id'].']"'.($field['required']?' required':'').($applicable?'':' disabled').'><option value="">Choose...</option><option value="Yes"'.($value==='Yes'?' selected':'').'>Yes</option><option value="No"'.($value==='No'?' selected':'').'>No</option></select>';else{$type=in_array($field['field_type'],['date','number','email','url'],true)?$field['field_type']:($field['field_type']==='currency'?'number':'text');echo '<input type="'.$type.'"'.($field['field_type']==='currency'?' step="0.01"':'').' name="custom_fields['.(int)$field['id'].']" value="'.e($value).'"'.($field['required']?' required':'').($field['validation_pattern']?' pattern="'.e($field['validation_pattern']).'"':'').($applicable?'':' disabled').'>';}echo '</label>';}echo '</div></section>';}
    echo '</div>';
