if($path==='/contacts') { require_permission('contacts.view');$q=trim((string)($_GET['q']??''));$tag=(int)($_GET['tag']??0);$recordView=(string)($_GET['view']??'mine');$contactStatus=(string)($_GET['contact_status']??($q!==''?'all':'active'));$older=max(0,min(3650,(int)($_GET['updated_older_days']??0)));$sql="SELECT DISTINCT c.* FROM contacts c LEFT JOIN contact_tags ct ON ct.contact_id=c.id WHERE 1";$args=[];if($q!==''){$sql.=' AND (c.first_name LIKE ? OR c.last_name LIKE ? OR c.company LIKE ? OR c.email LIKE ?)';$like="%$q%";$args=[$like,$like,$like,$like];}if($contactStatus==='active')$sql.=' AND c.active=1';elseif($contactStatus==='inactive')$sql.=' AND c.active=0';if($older)$sql.=" AND c.updated_at<DATE_SUB(NOW(),INTERVAL $older DAY)";if($tag){$sql.=' AND ct.tag_id=?';$args[]=$tag;}if($recordView!=='all'){$sql.=' AND COALESCE(c.owner_id,c.created_by)=?';$args[]=user()['id'];}$sql.=' ORDER BY c.updated_at DESC LIMIT 500';$s=db()->prepare($sql);$s->execute($args);$rows=array_values(array_filter($s->fetchAll(),fn($c)=>contact_access((int)$c['id'])!=='hidden'));
 layout('Contacts',function()use($rows,$q,$tag){?><div class="actions"><h1 style="margin:0">Contacts</h1><span class="spacer"></span><?php if(can('contacts.edit')):?><a class="btn secondary" href="/contacts/import">Import contacts</a><a class="btn" href="/contacts/new">Add contact</a><?php endif?></div><form class="card form-grid" method="get"><label>Search<input name="q" value="<?=e($q)?>" placeholder="Name, company, or email"></label><label>Tag<select name="tag"><option value="">All tags</option><?php foreach(all_tags() as $t)if(tag_access((int)$t['id'])!=='hidden'):?><option value="<?=$t['id']?>" <?=$tag===$t['id']?'selected':''?>><?=e($t['name'])?></option><?php endif?></select></label><div><button>Filter</button></div></form><div class="card"><table><thead><tr><th>Name</th><th>Company</th><th>Email</th><th>Tags</th><th>Last updated</th></tr></thead><tbody><?php foreach($rows as $c):?><tr><td><a href="/contacts/<?=$c['id']?>"><?=e($c['first_name'].' '.$c['last_name'])?></a></td><td><?=e($c['company'])?></td><td><?=e($c['email'])?></td><td><?php foreach(contact_tags((int)$c['id']) as $t)if(tag_access((int)$t['id'])!=='hidden'):?><span class="tag" style="background:<?=e($t['color'])?>"><?=e($t['name'])?></span><?php endif?></td><td><?=e($c['updated_at'])?></td></tr><?php endforeach?></tbody></table></div><?php });exit; }

if($path==='/contacts/new' || preg_match('#^/contacts/(\d+)/edit$#',$path,$m)){require_permission('contacts.edit');$id=isset($m[1])?(int)$m[1]:null;$isNew=$id===null;$c=$id?contact_row($id):[];if($id&&contact_access($id)!=='write'){http_response_code(403);exit('Read-only contact');}if($id)require_record_edit($c);
 if($method==='POST'){verify_csrf();if($id)require_record_edit($c);$vals=[trim(post('first_name')),trim(post('last_name')),trim(post('company')),trim(post('job_title')),trim(post('email')),trim(post('phone')),trim(post('address')),trim(post('website'))];if(!$vals[0]||!$vals[1]){flash('error','First and last name are required.');}else{if($id){$vals[]=$id;db()->prepare('UPDATE contacts SET first_name=?,last_name=?,company=?,job_title=?,email=?,phone=?,address=?,website=? WHERE id=?')->execute($vals);}else{$vals[]=user()['id'];$vals[]=user()['id'];db()->prepare('INSERT INTO contacts(first_name,last_name,company,job_title,email,phone,address,website,created_by,owner_id) VALUES(?,?,?,?,?,?,?,?,?,?)')->execute($vals);$id=(int)db()->lastInsertId();}db()->prepare('UPDATE contacts SET active=? WHERE id=?')->execute([post('active')?1:0,$id]);sync_contact_company($id,(string)$vals[2]);sync_tags($id,(array)post('tags',[]));if($isNew)apply_user_default_tags($id,user()['id']);save_contact_custom_values($id,(array)post('custom_fields',[]));if($c){$afterStmt=db()->prepare('SELECT * FROM contacts WHERE id=?');$afterStmt->execute([$id]);record_contact_changes($id,$c,$afterStmt->fetch()?:[]);}audit($c?'update':'create','contact',$id,['active'=>post('active')?1:0]);flash('success','Contact saved.');redirect('/contacts/'.$id);}}
 layout($id?'Edit contact':'New contact',function()use($c,$id){$selected=$id?array_column(contact_tags($id),'id'):[];if(!$id){$defaultStmt=db()->prepare('SELECT tag_id FROM user_default_tags WHERE user_id=?');$defaultStmt->execute([user()['id']]);$selected=$defaultStmt->fetchAll(PDO::FETCH_COLUMN);}$tagGroups=[];foreach(all_tags() as $tag)if(tag_access((int)$tag['id'])==='write')$tagGroups[$tag['group_name']??'Ungrouped'][]=$tag;$tagGroups['Ungrouped']??=[];?><h1><?=$id?'Edit contact':'New contact'?></h1><form class="card" id="contact-form" method="post" data-contact-id="<?=e($id?:0)?>"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><?php foreach(['first_name'=>'First name','last_name'=>'Last name','company'=>'Company','job_title'=>'Job title','email'=>'Email','phone'=>'Phone','website'=>'Website'] as $k=>$label):?><label><?=$label?><input name="<?=$k?>" value="<?=e($c[$k]??'')?>" <?=$k==='first_name'||$k==='last_name'?'required':''?>><?php if($k==='company'):?><div id="company-suggestions" class="company-suggestions" hidden></div><?php endif?></label><?php endforeach?><label class="full">Address<textarea name="address"><?=e($c['address']??'')?></textarea></label><div class="full"><span class="muted">Tags</span><div class="quick-tag"><input id="new-tag-name" type="text" placeholder="New tag name"><input id="new-tag-color" type="color" value="#1565c0" aria-label="Tag color"><button type="button" id="create-tag" class="secondary">Create tag</button><span id="tag-message" class="muted"></span></div><label>Search tags<input id="tag-search" type="search" placeholder="Type to filter tags or groups"></label><div class="tag-tree" id="contact-tags"><?php foreach($tagGroups as $group=>$groupTags):?><details data-tag-group <?=array_intersect(array_map(fn($item)=>(int)$item['id'],$groupTags),array_map('intval',$selected))?'open':''?>><summary><span class="folder-icon">▸</span> <?=e($group)?> <span class="muted">(<?=count($groupTags)?>)</span></summary><div class="checkboxes" <?=$group==='Ungrouped'?'id="tag-group-ungrouped"':''?>><?php foreach($groupTags as $t):?><label data-tag-text="<?=e(mb_strtolower($t['name'].' '.$group))?>"><input type="checkbox" name="tags[]" value="<?=$t['id']?>" <?=in_array($t['id'],$selected)?'checked':''?>><?=e($t['name'])?></label><?php endforeach?></div></details><?php endforeach?></div><?php render_contact_custom_fields($id,array_map('intval',$selected));?></div></div><div id="duplicate-warning" class="flash error" hidden></div><br><button>Save contact</button></form><script>function updateConditionalFields(){const selected=[...document.querySelectorAll("#contact-tags input:checked")].map(i=>i.value);document.querySelectorAll(".custom-field").forEach(field=>{const required=field.dataset.conditionTags?field.dataset.conditionTags.split(","):[];const show=!required.length||required.some(id=>selected.includes(id));field.hidden=!show;field.querySelectorAll("input,select,textarea").forEach(input=>input.disabled=!show)})}document.querySelector("#contact-tags")?.addEventListener("change",updateConditionalFields);updateConditionalFields();document.querySelector("#tag-search")?.addEventListener("input",e=>{const q=e.target.value.toLowerCase();document.querySelectorAll("#contact-tags [data-tag-group]").forEach(group=>{let matches=0;group.querySelectorAll("label").forEach(label=>{label.hidden=!label.dataset.tagText.includes(q);if(!label.hidden)matches++});group.hidden=!matches;if(q&&matches)group.open=true})});document.querySelector("#create-tag")?.addEventListener("click",async()=>{const n=document.querySelector("#new-tag-name"),c=document.querySelector("#new-tag-color"),m=document.querySelector("#tag-message"),b=document.querySelector("#create-tag");if(!n.value.trim()){m.textContent="Enter a tag name.";return}b.disabled=true;m.textContent="Creating…";const body=new URLSearchParams({_csrf:"<?=csrf()?>",name:n.value.trim(),color:c.value});try{const r=await fetch("/api/tags",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body});const d=await r.json();if(!r.ok)throw new Error(d.error||"Could not create tag.");const label=document.createElement("label"),box=document.createElement("input");box.type="checkbox";box.name="tags[]";box.value=d.id;box.checked=true;label.dataset.tagText=d.name.toLowerCase()+" ungrouped";label.append(box,document.createTextNode(d.name));document.querySelector("#tag-group-ungrouped").append(label);const ungrouped=document.querySelector("#tag-group-ungrouped").closest("details");ungrouped.hidden=false;ungrouped.open=true;updateConditionalFields();n.value="";m.textContent="Tag created and selected."}catch(e){m.textContent=e.message}finally{b.disabled=false}});</script><script>(()=>{const input=document.querySelector("[name=company]"),panel=document.querySelector("#company-suggestions");if(!input||!panel)return;let timer,request;input.addEventListener("input",()=>{clearTimeout(timer);panel.hidden=true;if(input.value.trim().length<2)return;timer=setTimeout(async()=>{request?.abort();request=new AbortController();try{const data=await fetch("/api/company-suggestions?q="+encodeURIComponent(input.value.trim()),{signal:request.signal}).then(r=>r.json());if(!data.suggestions.length)return;panel.replaceChildren();const title=document.createElement("strong");title.textContent="Did you mean?";panel.append(title);data.suggestions.forEach(s=>{const button=document.createElement("button");button.type="button";button.className="company-choice";button.textContent=s.name+" ("+s.contacts+" contact"+(s.contacts===1?"":"s")+")";button.onclick=()=>{input.value=s.name;panel.hidden=true};panel.append(button)});const keep=document.createElement("button");keep.type="button";keep.className="company-keep";keep.textContent="Keep “"+input.value.trim()+"” as a new company";keep.onclick=()=>panel.hidden=true;panel.append(keep);panel.hidden=false}catch(e){if(e.name!=="AbortError")panel.hidden=true}},350)})})();</script><script>(()=>{const form=document.querySelector('#contact-form'),warning=document.querySelector('#duplicate-warning');form?.addEventListener('submit',async e=>{if(form.dataset.duplicateConfirmed)return;e.preventDefault();const p=new URLSearchParams({exclude:form.dataset.contactId,first_name:form.first_name.value,last_name:form.last_name.value,email:form.email.value,phone:form.phone.value});const data=await fetch('/api/contact-duplicates?'+p).then(r=>r.json());if(!data.duplicates.length){form.dataset.duplicateConfirmed='1';form.requestSubmit();return}const lines=data.duplicates.map(d=>d.name+(d.company?' — '+d.company:'')+(d.email?' — '+d.email:''));if(confirm('Possible duplicate contact(s) found:\n\n'+lines.join('\n')+'\n\nChoose OK to create/update this contact anyway, or Cancel to review.')){form.dataset.duplicateConfirmed='1';form.requestSubmit()}else{warning.replaceChildren(document.createTextNode('Possible duplicates: '));data.duplicates.forEach((d,i)=>{if(i)warning.append(document.createTextNode(', '));const a=document.createElement('a');a.href='/contacts/'+d.id;a.target='_blank';a.textContent=d.name;warning.append(a)});warning.hidden=false;warning.scrollIntoView({behavior:'smooth'})}})})();</script><?php });exit;}

if(preg_match('#^/contacts/(\d+)$#',$path,$m)){$id=(int)$m[1];$c=contact_row($id);$access=contact_access($id);$notes=db()->prepare('SELECT n.*,u.username FROM notes n LEFT JOIN users u ON u.id=n.user_id WHERE contact_id=? ORDER BY created_at DESC');$notes->execute([$id]);$opps=db()->prepare('SELECT o.* FROM opportunities o JOIN opportunity_contacts oc ON oc.opportunity_id=o.id WHERE oc.contact_id=? ORDER BY o.created_at DESC');$opps->execute([$id]);$reminders=db()->prepare('SELECT * FROM reminders WHERE contact_id=? AND user_id=? AND completed_at IS NULL ORDER BY due_at');$reminders->execute([$id,user()['id']]);
 layout($c['first_name'].' '.$c['last_name'],function()use($c,$id,$access,$notes,$opps,$reminders){?><div class="actions"><h1 style="margin:0"><?=e($c['first_name'].' '.$c['last_name'])?></h1><span class="spacer"></span><?php if($access==='write'&&can('contacts.edit')):?><a class="btn" href="/contacts/<?=$id?>/edit">Edit</a><?php endif?></div><div class="grid"><div class="card"><h2>Contact</h2><p><?=e($c['job_title'])?><?=($c['job_title']&&$c['company'])?' at ':''?><?=e($c['company'])?></p><p><a href="mailto:<?=e($c['email'])?>"><?=e($c['email'])?></a><br><?=e($c['phone'])?><br><?=nl2br(e($c['address']))?></p><p class="muted">Created <?=e($c['created_at'])?> · Last updated <?=e($c['updated_at'])?></p><?php foreach(contact_tags($id) as $t)if(tag_access((int)$t['id'])!=='hidden'):?><span class="tag" style="background:<?=e($t['color'])?>"><?=e($t['name'])?></span><?php endif?></div><div class="card"><h2>Opportunities</h2><?php foreach($opps as $o):?><p><strong><?=e($o['title'])?></strong><br><span class="tag" style="background:<?=e(option_color('opportunity_score',$o['score']))?>"><?=e(option_label('opportunity_score',$o['score']))?></span> <?=e(option_label('opportunity_status',$o['status']))?> <?=isset($o['value'])?'$'.number_format((float)$o['value'],2):''?></p><?php endforeach?><?php if($access==='write'&&can('contacts.edit')):?><form method="post" action="/contacts/<?=$id?>/opportunities"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label>Title<input name="title" required></label><div class="form-grid"><label>Score<select name="score"><?php foreach(list_options('opportunity_score') as $option):?><option value="<?=e($option['code'])?>"><?=e($option['label'])?></option><?php endforeach?></select></label><label>Value<input type="number" step="0.01" name="value"></label></div><button>Add opportunity</button></form><?php endif?></div></div><?php render_contact_custom_values($id);?><div class="card"><h2>Notes</h2><?php foreach($notes as $n):?><div class="note"><?=nl2br(e($n['body']))?><div class="muted"><?=e($n['username'])?> · <?=e($n['created_at'])?></div></div><?php endforeach?><?php if($access==='write'&&can('contacts.edit')):?><form method="post" action="/contacts/<?=$id?>/notes"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label>Add note<textarea name="body" required></textarea></label><button>Add note</button></form><?php endif?></div><div class="card"><h2>Reminders</h2><?php foreach($reminders as $r):?><div class="note"><strong><?=e($r['message'])?></strong><div class="muted">Due <?=e($r['due_at'])?></div></div><?php endforeach?><form method="post" action="/contacts/<?=$id?>/reminders"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><label>Reminder message<input name="message" required></label><label>Target date and time<input type="datetime-local" name="due_at" required></label></div><button>Create reminder</button></form></div><?php });exit;}

if(preg_match('#^/contacts/(\d+)/(notes|opportunities)$#',$path,$m)&&$method==='POST'){require_permission($m[2]==='notes'?'contacts.view':'contacts.edit');verify_csrf();$id=(int)$m[1];$record=contact_row($id);if(contact_access($id)==='hidden'){http_response_code(403);exit('Forbidden');}if($m[2]==='notes'){db()->prepare('INSERT INTO notes(contact_id,user_id,body) VALUES(?,?,?)')->execute([$id,user()['id'],trim(post('body'))]);audit('create','note',null,['contact_id'=>$id]);}else{require_record_edit($record);$score=(string)post('score');if(!in_array($score,option_codes('opportunity_score'),true))$score=option_codes('opportunity_score')[0]??'medium';db()->prepare('INSERT INTO opportunities(contact_id,owner_id,created_by,title,score,value) VALUES(?,?,?,?,?,?)')->execute([$id,user()['id'],user()['id'],trim(post('title')),$score,post('value')?:null]);$oid=(int)db()->lastInsertId();db()->prepare('INSERT INTO opportunity_contacts(opportunity_id,contact_id) VALUES(?,?)')->execute([$oid,$id]);audit('create','opportunity',$oid,['contact_id'=>$id]);}redirect('/contacts/'.$id);}

if(preg_match('#^/contacts/(\d+)/reminders$#',$path,$m)&&$method==='POST'){
    require_permission('contacts.view');verify_csrf();$id=(int)$m[1];contact_row($id);
    require_permission('alerts.edit');
    $message=trim((string)post('message'));$due=str_replace('T',' ',(string)post('due_at'));
    if($message===''||!strtotime($due)){flash('error','Reminder message and date are required.');redirect('/contacts/'.$id);}
    db()->prepare('INSERT INTO reminders(contact_id,user_id,message,due_at) VALUES(?,?,?,?)')->execute([$id,user()['id'],$message,$due]);
    audit('create','reminder',(int)db()->lastInsertId(),['contact_id'=>$id]);flash('success','Reminder created.');redirect('/contacts/'.$id);
}

